[CmdletBinding()]param([Parameter(Mandatory)][string]$InputPath,[string]$SignToolPath,[switch]$RequireSigned)
$ErrorActionPreference='Stop';$s=Get-AuthenticodeSignature $InputPath;if($RequireSigned-and$s.Status-ne'Valid'){throw "Authenticode status: $($s.Status)"};if($s.Status-eq'Valid'-and-not$s.TimeStamperCertificate){throw 'Timestamp missing.'};if($SignToolPath){& $SignToolPath verify /pa /tw /v $InputPath;if($LASTEXITCODE){throw 'SignTool verification failed.'}};[pscustomobject]@{Status=$s.Status;Signer=$s.SignerCertificate.Subject;Timestamp=$s.TimeStamperCertificate.Subject;SHA256=(Get-FileHash $InputPath -Algorithm SHA256).Hash}
